const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/Users/emofficemba/ai-content-farm/config/master-config.json', 'utf8'));

const items = [];
for (const [key, persona] of Object.entries(config.personas)) {
  if (persona.active) {
    items.push({
      json: {
        persona_key: key,
        persona_name: persona.name,
        ig_handle: persona.ig_handle,
        gender: persona.gender,
        style_tags: persona.style_tags,
        outfit_prefs: persona.outfit_preferences,
        locations: persona.locations,
        photo_specs: config.system.photography,
        lens_rotation: config.system.lens_rotation_groups
      }
    });
  }
}
return items;

const persona = $input.first().json.persona_name;
const concept = $input.first().json.concept || {};
const gender = $input.first().json.gender || 'female';

// 語錄式 caption 模板
const captions = [];

// Caption 1: 感性治癒
const mood = gender === 'female' 
  ? ['柔軟', '溫暖', '細膩', '精致', '自在']
  : ['干練', '沉穩', '瀑洗', '坤士', '瀑流'];
const m1 = mood[Math.floor(Math.random() * mood.length)];
captions.push(`${m1}是一種選擇，也是一種力量。

今天的我，選擇了${concept.outfit || '喜歡的樣子'}。

你們今天選擇了什麼？`);

// Caption 2: 場景感慨
const places = concept.location ? concept.location.split(/[,，]/) : ['這裡'];
const place = places[0].trim();
captions.push(`每一次來${place}，都覺得被治癒了一點。

陽光、風、還有這身${concept.outfit || '簡單的穿搭'}——不用太用力，就能融入。

你們最愛的小地方是哪裡？`);

// Caption 3: 自我表達
const verbs = gender === 'female'
  ? ['笑得很甜', '走得很慢', '看得很遠']
  : ['跑得很快', '站得很直', '想得很透'];
const v1 = verbs[Math.floor(Math.random() * verbs.length)];
captions.push(`有些時候，美不是穿什麼，而是怎麼感受自己。

${v1}，就是今天最好的樣子。

告訴我，你們今天過得怎麼樣？`);

return [{
  json: {
    persona: $input.first().json.persona_name,
    persona_key: $input.first().json.persona_key,
    ig_handle: $input.first().json.ig_handle,
    concept: concept,
    lenses: $input.first().json.lenses || ['90mm','50mm','35mm','28mm'],
    captions: captions,
    photo_specs: $input.first().json.photo_specs,
    generated_at: new Date().toISOString()
  }
}];

